INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, "2025/01/31 12:00:00", 1000001, -416.5, 1, "2030/01/01 14:59:59", 62, "カリン", 3.414, 1, 190801, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", 2, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, "2025/01/31 12:00:00", 1000002, -416.5, 2, "2030/01/01 14:59:59", 62, "カリン", 3.099, 1, 190801, "ミッションをクリアして、\n報酬をゲットしましょう！", 2, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, "2025/01/31 12:00:00", 1000003, -416.5, 3, "2030/01/01 14:59:59", 63, "カリン", 2.801, 1, 190801, "受け取ることができる\n報酬があるようです\n確認してみてください", 2, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, "2025/01/31 12:00:00", 1000004, -416.5, 4, "2030/01/01 14:59:59", 63, "カリン", 0.0, 1, 190801, "報酬がもらえますよ！\nチェックしてみてください", 2, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, "2025/01/31 12:00:00", 1000005, -363.0, 5, "2030/01/01 14:59:59", 64, "カリン", 2.12, 1, 190801, "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", 1, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, "2025/01/31 12:00:00", 1000006, -363.0, 6, "2030/01/01 14:59:59", 64, "カリン", 1.68, 1, 190801, "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", 2, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, "2025/01/31 12:00:00", 1000007, -363.0, 7, "2030/01/01 14:59:59", 64, "カリン", 2.33, 1, 190801, "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", 1, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (3, "2025/01/31 12:00:00", 1020101, -285.0, 101, "2030/01/01 14:59:59", 61, "ラビリスタ", 5.18, 10201, 133701, "今度の敵は、アタシにとっても\n放ってはおけない存在だ\n少年、アタシも全力で行くからさ\n一緒に守ろう、この世界を", 7, -6.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, "2025/01/31 12:00:00", 1020102, -285.0, 201, "2030/01/01 14:59:59", 61, "クリスティーナ", 8.77, 10201, 133901, "退屈の吹き飛ぶような\n戦いの気配がするなぁ坊や\nさっさとワタシをそこへ連れてゆけ\n世界も守ってやるさ、ついでにな", 2, -2.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (6, "2025/01/31 12:00:00", 1020103, -285.0, 301, "2030/01/01 14:59:59", 61, "ネネカ", 15.5, 10201, 133801, "おや、私の力が必要……と？\nグレゴールが手伝うそうですよ\n私は戦わないのか、という顔ですね\n……考えておきます", 1, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, "2025/02/28 12:00:00", 1020201, -285.0, 101, "2030/01/01 14:59:59", 61, "ランファ", 9.061, 10202, 134301, "わたしだけの歌…\n一緒に、探してくれる…？\nあなたがいれば…\nもっとがんばれるから…", 5, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, "2025/02/28 12:00:00", 1020202, -285.0, 201, "2030/01/01 14:59:59", 61, "チカ", 7.699, 10202, 134401, "同じ唱喚士として、仲間として\n私にできることをします\n…これも、あなたが\n背中を押してくれたおかげですよ", 2, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, "2025/03/31 12:00:00", 1020301, -285.0, 101, "2030/01/01 14:59:59", 61, "アオイ", 8.595, 10203, 134601, "世界の平和が私とクローチェさんに\nかかってるんですよね？\nぼっちには過大すぎる期待ですけど\nふ、二人でなら背負ってみせます！", 2, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, "2025/03/31 12:00:00", 1020302, -285.0, 201, "2030/01/01 14:59:59", 61, "クローチェ", 7.758, 10203, 134501, "新しく手に入れたこの翼で…\nナイトさんがどこにいたって\nわたし、駆けつけちゃいますよっ！\nクローチェ・エアリアル発進ですっ", 2, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, "2025/04/30 12:00:00", 1020401, -285.0, 101, "2030/01/01 14:59:59", 61, "ルイズマリー", 7.0, 10204, 132302, "今日はダーリンとの初デート♪\n二人でショッピングして、その後は\n…って私、指名手配されてる！？\nちょ、た…助けてダーリン～！！", 6, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, "2025/04/30 12:00:00", 1020402, -285.0, 201, "2030/01/01 14:59:59", 61, "イロハ", 7.904, 10204, 132402, "ルイちゃんのおばあちゃん優しくて\nいつもにこにこで、イロハ大好き♪\nでも一番好きなのは、角がすっごく\n大きくてかっこいいとこなんだ～♪", 2, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (4, "2025/04/30 12:00:00", 1020403, -285.0, 301, "2030/01/01 14:59:59", 61, "ソノ", 8.487, 10204, 132502, "ノゾミちゃんのおかげで売上が安定\nしてきたのに、臨時休業、痛すぎる\n…ま、ルイちゃんのために\n一肌脱ぐか。行くよイロハ～", 2, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, "2025/05/31 12:00:00", 1020502, -285.0, 101, "2030/01/01 14:59:59", 61, "カノン", 8.763, 10205, 134901, "ヲ～ッホッホ♪\nあたくし様と同じお空気を吸える\nお幸運を噛みしめなさいですわ～♪\nヲ～ッホッホッホ～♪", 2, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, "2025/05/31 12:00:00", 1020503, -285.0, 201, "2030/01/01 14:59:59", 61, "ツムギ", 6.417, 10205, 134801, "いきますよ騎士さん！\nカノンさんと力を合わせて…力を…\n…本当にあの人なんなんです？\nこれまでになく不安なんですけど！", 3, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (3, "2025/06/30 12:00:00", 1020601, -285.0, 101, "2030/01/01 14:59:59", 61, "エリス", 10.335, 10206, 135001, "『願いが叶う海岸』か…怪しい\nだというのに、阿賀斗紫布菜たちは\n呑気に戯れている…見ていられない\n騎士クンは、わたしが守ってみせる", 7, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, "2025/06/30 12:00:00", 1020602, -285.0, 201, "2030/01/01 14:59:59", 61, "シェフィ", 6.281, 10206, 135101, "せっかくの夏休みなんだし\nたまにはビーチでゆっくりしましょ\n…え、もしかしてこの夏もあんまり\n休めなかったりする感じなの？", 4, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, "2025/06/30 12:00:00", 1020603, -285.0, 301, "2030/01/01 14:59:59", 61, "プレシア", 12.244, 10206, 135201, "いっぱい。たべて\nおおきく。なると\nせーぎ。まもれる。はず\nお兄。いっしょに。スイカ。たべよ", 2, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, "2025/07/31 12:00:00", 1020701, -285.0, 101, "2030/01/01 14:59:59", 61, "クリア", 6.339, 10207, 135301, "ひと夏の冒険のはじまりです！\nアネモネさんも楽しんでくれたら\n…できれば、もう少し\n仲良くなれたらうれしいな…", 8, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (7, "2025/07/31 12:00:00", 1020702, -285.0, 201, "2030/01/01 14:59:59", 61, "アネモネ", 8.184, 10207, 135401, "─幻の花…\n本当にあるのか謎─ですけど\n探すくらいは、\n付き合ってもいいです", 9, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (9, "2025/08/31 12:00:00", 1020801, -285.0, 101, "2030/01/01 14:59:59", 61, "アイラ", 3.906, 10208, 129101, "あははっ！　笑う門には福来る！\n笑ってればきっと、複製世界にも\n未来はやってくるって信じてる！\nそうだよね、シナツちゃん！", 2, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, "2025/08/31 12:00:00", 1020802, -285.0, 201, "2030/01/01 14:59:59", 61, "シナツ", 14.465, 10208, 129201, "繰り返されるリセットの先の未来\n何度願っても手に入らなかった未来\n…でも、私は諦めない。絶対にだ\nキミも同じだろ…アイラ？", 2, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (4, "2025/08/31 12:00:00", 1020803, -285.0, 301, "2030/01/01 14:59:59", 61, "ヒヨリ", 8.662, 10208, 100101, "アイラの世界のみんなも、\n一生懸命生きてるんだ…！\n…なのに、世界の危機だなんて！\nあたし、絶対、絶対力になるよ！", 3, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, "2025/08/31 12:00:00", 1020804, -285.0, 401, "2030/01/01 14:59:59", 61, "レイ", 10.915, 10208, 100301, "シナツ…もう一人の私\n彼女が大切にしている世界を\n絶対に終わらせはしない…！\n彼女と笑い合える未来のために！", 3, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, "2025/09/30 12:00:00", 1020901, -285.0, 101, "2030/01/01 14:59:59", 61, "ユキノ", 6.042, 10209, 135802, "あ、ど、ども…\nあ、あんま見ねぇでくれっと\nその、恥ずかしくて…\n体が熱くなって、溶けちまう…", 7, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (4, "2025/09/30 12:00:00", 1020902, -285.0, 201, "2030/01/01 14:59:59", 61, "サツキ", 9.402, 10209, 135903, "なんで俺が幽霊に…意味不明だ\nこれじゃ死んでも死にきれねェ\n悪ィがこれも何かの縁だ、\nよろしく頼むぜ騎士公", 1, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (8, "2025/09/30 12:00:00", 1020903, -285.0, 301, "2030/01/01 14:59:59", 61, "ルルィ", 8.16, 10209, 136902, "う、うじゅる…\nサツキ姉しゃまを助けるためにも\nまずは、腹ごしらえでしゅね…！\nタコ焼き、召し上がってくだしゃい", 1, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (3, "2025/10/31 12:00:00", 1021001, -285.0, 101, "2030/01/01 14:59:59", 61, "カスミ", 5.0, 10210, 137401, "ひさしぶりのジオ・ゲヘナ\n歓迎パーティーで起きた殺人事件！\nランドソルの名探偵の名にかけて\n解き明かしてみせようじゃないか！", 2, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (4, "2025/10/31 12:00:00", 1021002, -285.0, 201, "2030/01/01 14:59:59", 61, "アラクネ", 8.12, 10210, 136001, "…わたしはどこの誰なのでしょう\nどこから来てどこへ行くのでしょう\nこの事件の真相が分かれば、\n何かが掴めるような気がいたします", 1, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (4, "2025/10/31 12:00:00", 1021003, -285.0, 301, "2030/01/01 14:59:59", 61, "ナーナ", 6.386, 10210, 136202, "ナーナ、すいりとかろんぱとか、\nむずかしくてわかんないけど…\nお友だちとドーナツのためならっ\nせーいっぱいがんばるよっ！", 2, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (3, "2025/11/30 12:00:00", 1021101, -285.0, 101, "2030/01/01 14:59:59", 61, "ユイ", 7.438, 10211, 136402, "騎士クンに想いを伝えたい…だから\nミソラちゃん、わたしがんばるね！\n…あれ？　わたし、なんでこんなに\n必死になってるんだろう…？", 4, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, "2025/11/30 12:00:00", 1021102, -285.0, 201, "2030/01/01 14:59:59", 61, "ミソラ", 8.35, 10211, 136302, "騎士さんとのデートはわたしに\nお任せです★　なのでユイさんは\n安心して計画に専念して…たくさん\nドキドキしちゃってくださいね", 5, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, "2025/12/31 12:00:00", 1021201, -285.0, 101, "2030/01/01 14:59:59", 61, "シズル", 5.0, 10212, 136501, "新しい年がやってくるね！\nお正月の料理も飾りつけも、\nお姉ちゃんにお任せだよ♪\nみんなで楽しく新年を迎えよう！", 2, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, "2025/12/31 12:00:00", 1021202, -285.0, 201, "2030/01/01 14:59:59", 61, "リノ", 5.25, 10212, 137902, "おうちの掃除もトラブルも、 \n世界を揺るがす大ピンチも！\n今年のことは今年のうちに \nサッサと片付けちゃいますっ！", 2, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, "2025/12/31 12:00:00", 1021203, -285.0, 301, "2030/01/01 14:59:59", 61, "ラビリスタ", 7.5, 10212, 106801, "年の瀬はギルドマスターも\nつい駆け回っちゃう忙しい時期だ！\n一年いろいろあったけど\nお互いイイ年を迎えよう、少年！", 2, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, "2026/01/31 12:00:00", 1021301, -285.0, 101, "2030/01/01 14:59:59", 61, "ライラエル", 8.204, 10213, 126501, "漂う異国の料理の香り…それだけで\n世界中を旅した気分に浸れますね\nふふ、ほらクローチェ\nあまりはしゃぎすぎないように…♪", 2, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, "2026/01/31 12:00:00", 1021302, -285.0, 201, "2030/01/01 14:59:59", 61, "ネフィ＝ネラ", 7.176, 10213, 129701, "異界の姫君と煮炊きにて競い合う…\n感奮興起、いとをかし\n華やかなる祭典と相成るよう、一肌\n脱がせていただきとう存じまする", 2, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, "2026/01/31 12:00:00", 1021303, -285.0, 301, "2030/01/01 14:59:59", 61, "ヴァイオレット", 8.602, 10213, 133101, "『ビストロプリンセス』のために\n料理の特訓を重ねてまいりました\nこの料理で騎士様の…い、いえ\n皆様の心とお腹を満たしますわ！", 5, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, "2026/02/06 12:00:00", 1021304, -285.0, 102, "2030/01/01 14:59:59", 61, "ライラエル", 10.14, 10213, 138101, "多様な味わいが織りなすハーモニー\nそれこそが我が国の矜持です\nもしもそれを乱すようであれば\nわたしも優しくはありませんよ？", 3, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, "2026/02/06 12:00:00", 1021305, -285.0, 202, "2030/01/01 14:59:59", 61, "ネフィ＝ネラ", 10.152, 10213, 138201, "煉獄の穢土にてひと際輝く民草の心\n此れを守護りまするがわっちの責務\n如何な困難待ち受けようと\n不退転の矜持に揺らぎはありんせん", 7, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (4, "2026/02/06 12:00:00", 1021306, -285.0, 302, "2030/01/01 14:59:59", 61, "ヴァイオレット", 9.688, 10213, 138001, "裏世界の皆様は危機を脱し、\n残るはランドソルの皆様のみ…\n彼らを救い出すために、どうか…\nお立ち下さいペコリーヌ姫…！", 3, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, "2026/02/12 12:00:00", 1021307, -285.0, 401, "2030/01/01 14:59:59", 61, "ペコリーヌ", 5.928, 10213, 138301, "みなさん、お待たせしちゃいました\nペコリーヌ、完全復活です☆\nみなさんの食卓を守るため\nもう二度と、わたしはめげません！", 1, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (4, "2026/02/28 12:00:00", 1021401, -285.0, 101, "2030/01/01 14:59:59", 61, "ワカナ", 9.19, 10214, 138702, "成行きで参加することになっちゃっ\nた尻相撲大会。ううっ、恥ずかしい\nけどやるしかないよね。…騎士さん\nいっぱい応援してくださいね？", 2, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, "2026/02/28 12:00:00", 1021402, -285.0, 201, "2030/01/01 14:59:59", 61, "シオリ", 8.724, 10214, 138802, "「お姉ちゃんを守れる自分になる」\nあの日の約束、今こそ果たしてみせ\nます。例えお姉ちゃんに背くことに\nなっても。例えそれが尻相撲でも！", 3, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (4, "2026/03/31 12:00:00", 1021501, -285.0, 101, "2030/01/01 14:59:59", 61, "グレイス", 7.758, 10215, 138902, "私がへんたいふしんしゃさんって…\nただ生きているだけなのに、ひどい\n…まぁ死んでるんですけど…とか\n言ってる暇もない感じですか？", 1, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (6, "2026/03/31 12:00:00", 1021502, -285.0, 201, "2030/01/01 14:59:59", 61, "キョウカ", 6.375, 10215, 139002, "あの、助けてください！\n私がへんたいふしんしゃさんに\nなっちゃったみたいなんです…！\nどういう意味かは私もわかりません", 4, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (6, "2026/03/31 12:00:00", 1021503, -285.0, 301, "2030/01/01 14:59:59", 61, "ルルィ", 6.173, 10215, 136902, "ましゃか、グレイス姉しゃまたちが\nへんたいふしんしゃさんだなんて…\n騎士しゃん。あたちたちも協力ちて\n二人の破滅エンドを回避ちましょう", 1, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (6, "2026/04/30 12:00:00", 1021601, -285.0, 101, "2030/01/01 14:59:59", 61, "ミホ", 4.202, 10216, 139202, "違う世界に来ちゃうし、\n驚きの連続だけど…\nわたしも精いっぱい頑張ります！\nアストルムのみんなと一緒に！", 2, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (6, "2026/04/30 12:00:00", 1021602, -285.0, 201, "2030/01/01 14:59:59", 61, "マホ", 2.842, 10216, 139302, "想定外の事象が発生したな…だが\nいかなる苦境も切り抜けてみせる\nいつもの自分とは違う姿になっても\nわたしはわたし、西住流だ", 1, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (4, "2026/04/30 12:00:00", 1021603, -285.0, 301, "2030/01/01 14:59:59", 61, "エリカ", 4.598, 10216, 139402, "何でこんなことになっているのか\n全然わからないけど、迷ってる暇は\nないわ。黒森峰の次期隊長として、\n前進あるのみ！　これも戦車道よ！", 1, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, "2026/04/10 12:00:00", 2000001, -416.5, 1, "2030/01/01 14:59:59", 62, "カリン", 3.414, 2, 190801, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", 2, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, "2026/04/10 12:00:00", 2000002, -416.5, 2, "2030/01/01 14:59:59", 62, "カリン", 3.099, 2, 190801, "ミッションをクリアして、\n報酬をゲットしましょう！", 2, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, "2026/04/10 12:00:00", 2000003, -416.5, 3, "2030/01/01 14:59:59", 63, "カリン", 2.801, 2, 190801, "受け取ることができる\n報酬があるようです\n確認してみてください", 2, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, "2026/04/10 12:00:00", 2000004, -416.5, 4, "2030/01/01 14:59:59", 63, "カリン", 0.0, 2, 190801, "報酬がもらえますよ！\nチェックしてみてください", 2, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, "2026/04/10 12:00:00", 2000005, -363.0, 5, "2030/01/01 14:59:59", 64, "カリン", 2.12, 2, 190801, "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", 1, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, "2026/04/10 12:00:00", 2000006, -363.0, 6, "2030/01/01 14:59:59", 64, "カリン", 1.68, 2, 190801, "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", 2, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, "2026/04/10 12:00:00", 2000007, -363.0, 7, "2030/01/01 14:59:59", 64, "カリン", 2.33, 2, 190801, "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", 1, 0.0);
